using ExpenseTracker.Domain.Enums;
namespace ExpenseTracker.Domain.Entities;
public sealed class User { public Guid Id {get;set;}=Guid.NewGuid(); public string FullName {get;set;}=""; public string Email {get;set;}=""; public string PasswordHash {get;set;}=""; public string? Avatar {get;set;} public DateTime CreatedAt {get;set;}=DateTime.UtcNow; public ICollection<Category> Categories { get; set; } = new List<Category>(); public ICollection<Transaction> Transactions { get; set; } = new List<Transaction>(); public ICollection<Budget> Budgets { get; set; } = new List<Budget>(); }
public sealed class Category { public Guid Id {get;set;}=Guid.NewGuid(); public Guid UserId {get;set;} public string Name {get;set;}=""; public TransactionType Type {get;set;} public string Icon {get;set;}="tag"; public string Color {get;set;}="#635BFF"; public User User { get; set; } = null!; public ICollection<Transaction> Transactions { get; set; } = new List<Transaction>(); public ICollection<Budget> Budgets { get; set; } = new List<Budget>(); }
